/// Context information passed to all visitor methods.
///
/// Provides comprehensive metadata about the current node being visited,
/// including its type, tag name, position in the DOM tree, and parent context.
///
/// ## Attributes
///
/// Access attributes via `NodeContext.attributes`, which returns
/// `&BTreeMap<String, String>`. When the context was built with
/// `NodeContext.with_lazy_attributes` (the hot path inside the converter),
/// the map is only materialized on the first call — if the visitor never reads
/// attributes, the allocation is skipped.
///
/// ## Lifetimes
///
/// String fields use `Cow<'_, str>` so the converter can pass slices directly
/// out of the parsed DOM without allocating. Visitor implementations that need
/// to outlive the callback should call `NodeContext.into_owned`.
#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
#[napi(object, js_name = "NodeContext")]
pub struct JsNodeContext {
    /// Coarse-grained node type classification
    #[napi(js_name = "nodeType")]
    #[serde(rename = "nodeType")]
    pub node_type: JsNodeType,
    /// Raw HTML tag name (e.g., "div", "h1", "custom-element")
    #[napi(js_name = "tagName")]
    #[serde(rename = "tagName")]
    pub tag_name: String,
    /// Depth in the DOM tree (0 = root)
    pub depth: i64,
    /// Index among siblings (0-based)
    #[napi(js_name = "indexInParent")]
    #[serde(rename = "indexInParent")]
    pub index_in_parent: i64,
    /// Parent element's tag name (None if root)
    #[napi(js_name = "parentTag")]
    #[serde(rename = "parentTag")]
    pub parent_tag: Option<String>,
    /// Whether this element is treated as inline vs block
    #[napi(js_name = "isInline")]
    #[serde(rename = "isInline")]
    pub is_inline: bool,
}

/// Construct a `NodeContext` with an owned attribute map.
///
/// Prefer `NodeContext.with_lazy_attributes` (pub(crate)) inside the
/// converter to avoid the eager `collect_tag_attributes` allocation.
#[napi(js_name = "nodeContextWithOwnedAttributes")]
pub fn node_context_with_owned_attributes(
    node_type: JsNodeType,
    tag_name: String,
    attributes: HashMap<String, String>,
    depth: i64,
    index_in_parent: i64,
    parent_tag: Option<String>,
    is_inline: bool,
) -> JsNodeContext {
    html_to_markdown_rs::NodeContext::with_owned_attributes(
        node_type.into(),
        tag_name.into(),
        attributes.into_iter().collect::<std::collections::BTreeMap<_, _>>(),
        depth as usize,
        index_in_parent as usize,
        parent_tag.map(std::borrow::Cow::Owned),
        is_inline,
    )
    .into()
}
/// Promote any borrowed fields into owned storage so the context can outlive `'a`.
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "nodeContextIntoOwned")]
pub fn node_context_into_owned(cfg: JsNodeContext) -> napi::Result<JsNodeContext> {
    let _json =
        serde_json::to_string(&cfg).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _core: html_to_markdown_rs::NodeContext =
        serde_json::from_str(&_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _result = _core.into_owned();
    let _out_json =
        serde_json::to_string(&_result).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    serde_json::from_str(&_out_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

