impl From<html_to_markdown_rs::VisitResult> for JsVisitResult {
    fn from(val: html_to_markdown_rs::VisitResult) -> Self {
        match val {
            html_to_markdown_rs::VisitResult::Continue => Self::Continue,
            html_to_markdown_rs::VisitResult::Custom(..) => Self::Custom,
            html_to_markdown_rs::VisitResult::Skip => Self::Skip,
            html_to_markdown_rs::VisitResult::PreserveHtml => Self::PreserveHtml,
            html_to_markdown_rs::VisitResult::Error(..) => Self::Error,
        }
    }
}

// Error variant name constants
pub const CONVERSION_ERROR_ERROR_PARSE_ERROR: &str = "ParseError";
pub const CONVERSION_ERROR_ERROR_SANITIZATION_ERROR: &str = "SanitizationError";
pub const CONVERSION_ERROR_ERROR_CONFIG_ERROR: &str = "ConfigError";
pub const CONVERSION_ERROR_ERROR_IO_ERROR: &str = "IoError";
pub const CONVERSION_ERROR_ERROR_PANIC: &str = "Panic";
pub const CONVERSION_ERROR_ERROR_INVALID_INPUT: &str = "InvalidInput";
pub const CONVERSION_ERROR_ERROR_OTHER: &str = "Other";

/// Convert a `html_to_markdown_rs::error::ConversionError` error to a NAPI error.
#[allow(dead_code)]
fn conversion_error_to_napi_err(e: html_to_markdown_rs::error::ConversionError) -> napi::Error {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        html_to_markdown_rs::error::ConversionError::ParseError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ParseError] {}", msg))
        }
        html_to_markdown_rs::error::ConversionError::SanitizationError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[SanitizationError] {}", msg))
        }
        html_to_markdown_rs::error::ConversionError::ConfigError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ConfigError] {}", msg))
        }
        html_to_markdown_rs::error::ConversionError::IoError(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[IoError] {}", msg))
        }
        html_to_markdown_rs::error::ConversionError::Panic(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Panic] {}", msg))
        }
        html_to_markdown_rs::error::ConversionError::InvalidInput(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[InvalidInput] {}", msg))
        }
        html_to_markdown_rs::error::ConversionError::Other(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Other] {}", msg))
        }
        _ => napi::Error::new(napi::Status::GenericFailure, msg),
    }
}
